def process_data(df):
    min_score = float(get_env('MIN_SCORE', '0'))
    if min_score > 0 and 'max_score' in df.columns:
        df = df[df['max_score'].fillna(0).astype(float) >= min_score]
    if 'box_count' in df.columns:
        df = df[df['box_count'].fillna(0).astype(float) > 0]
    elif 'check_status' in df.columns:
        df = df[df['check_status'].astype(str).isin(['1', 'true', 'True'])]
    product_type = get_env('PRODUCT_TYPE', '').strip()
    if product_type and 'product_type' in df.columns:
        df = df[df['product_type'].astype(str) == product_type]
    return df.reset_index(drop=True)
